    ObservableList inventoryList
}

Item --|> InventoryController : extends
FileUtil --|> InventoryController : implements

class Item <<C>> {
    String name
    String serialNumber
    BigDecimal price

    get()
    set()
    toString()
}

interface FileLoader <<I>> {
    readFromTXT()
    readFromHTML()
    readFromJSON()
}

interface FileSaver <<I>> {
    writeToTxt()
    writeTtoHTML()
    writeToJSON()
}

abstract class FileUtils <<A>> {
    +readToText(): void
    #writeToFile(String): boolean
}

